"use strict";(globalThis.webpackChunkmythogen_engine_blog=globalThis.webpackChunkmythogen_engine_blog||[]).push([[5141],{7494(e,n,t){t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>a,default:()=>d,frontMatter:()=>o,metadata:()=>r,toc:()=>h});var s=t(4848),i=t(8453);const o={},a="Chapter 8: The Only Arsenal \u2014 TSMC's Ultimate Monopoly",r={id:"GameVictory/\u7b2c\u516b\u7ae0_\u552f\u4e00\u7684\u8ecd\u5de5\u5ee0_\u53f0\u7a4d\u96fb\u7684\u7d42\u6975\u58df\u65b7_v2",title:"Chapter 8: The Only Arsenal \u2014 TSMC's Ultimate Monopoly",description:"In the autumn of 2025, an NVIDIA supply chain manager sat in a cafe near the Hsinchu Science Park, waiting for his TSMC contact to reply to an email. The content of the email was simple: Could the production schedule for the next batch of B200 AI chips be moved up by two weeks?",source:"@site/i18n/en/docusaurus-plugin-content-docs/current/GameVictory/\u7b2c\u516b\u7ae0_\u552f\u4e00\u7684\u8ecd\u5de5\u5ee0_\u53f0\u7a4d\u96fb\u7684\u7d42\u6975\u58df\u65b7_v2.md",sourceDirName:"GameVictory",slug:"/GameVictory/\u7b2c\u516b\u7ae0_\u552f\u4e00\u7684\u8ecd\u5de5\u5ee0_\u53f0\u7a4d\u96fb\u7684\u7d42\u6975\u58df\u65b7_v2",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u516b\u7ae0_\u552f\u4e00\u7684\u8ecd\u5de5\u5ee0_\u53f0\u7a4d\u96fb\u7684\u7d42\u6975\u58df\u65b7_v2",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"docs",previous:{title:'Chapter 7: The CUDA Gamble and the Gamers\' "R&D Tax"',permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e03\u7ae0_CUDA\u8c6a\u8ced\u8207\u904a\u6232\u73a9\u5bb6\u7684RD\u7a05_v3"},next:{title:"Chapter 9: A Tale of Two CEOs \u2014 Lisa Su vs. Pat Gelsinger",permalink:"/MythogenEngine/en/docs/GameVictory/\u7b2c\u4e5d\u7ae0_CEO\u7684\u751f\u6b7b\u6642\u901f_Lisa_Su_vs_Pat_Gelsinger_v2"}},l={},h=[{value:"I. An Uncomfortable Fact",id:"i-an-uncomfortable-fact",level:2},{value:"II. Four Types of Chips, Four Types of Exam Papers",id:"ii-four-types-of-chips-four-types-of-exam-papers",level:2},{value:"III. The Moat of Trust",id:"iii-the-moat-of-trust",level:2},{value:"IV. Gaming&#39;s Invisible Bill",id:"iv-gamings-invisible-bill",level:2},{value:"V. Closing Arguments",id:"v-closing-arguments",level:2},{value:"VI. The Loot is Still Being Divided",id:"vi-the-loot-is-still-being-divided",level:2}];function c(e){const n={h1:"h1",h2:"h2",header:"header",hr:"hr",img:"img",li:"li",ol:"ol",p:"p",strong:"strong",ul:"ul",...(0,i.R)(),...e.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(n.header,{children:(0,s.jsx)(n.h1,{id:"chapter-8-the-only-arsenal--tsmcs-ultimate-monopoly",children:"Chapter 8: The Only Arsenal \u2014 TSMC's Ultimate Monopoly"})}),"\n",(0,s.jsx)(n.p,{children:"In the autumn of 2025, an NVIDIA supply chain manager sat in a cafe near the Hsinchu Science Park, waiting for his TSMC contact to reply to an email. The content of the email was simple: Could the production schedule for the next batch of B200 AI chips be moved up by two weeks?"}),"\n",(0,s.jsx)(n.p,{children:"He waited three days. The answer was no."}),"\n",(0,s.jsx)(n.p,{children:"Not because TSMC didn't want to, but because ahead of NVIDIA on the production line were Apple's A19 Pro, AMD's next-generation EPYC server processors, Qualcomm's flagship mobile chips, and several clients whose names he was not permitted to know. Everyone was rushing them. Everyone felt their chips were the most important. But the factories in the world capable of manufacturing these chips\u2014capable of etching tens of billions of transistors onto a twelve-inch wafer using a 3-nanometer process with a yield high enough for commercial mass production\u2014there was only one."}),"\n",(0,s.jsx)(n.p,{children:"Just this one."}),"\n",(0,s.jsx)(n.p,{children:"Not in Silicon Valley. Not in Tokyo. Not in Seoul. Not in Berlin."}),"\n",(0,s.jsx)(n.p,{children:"In Hsinchu."}),"\n",(0,s.jsx)(n.p,{children:"The previous chapter described a four-layer-deep software prison\u2014CUDA locking in hardware instruction sets, libraries, frameworks, and AI engineers worldwide. That prison is invisible; it is built out of code."}),"\n",(0,s.jsx)(n.p,{children:"This chapter is about a tangible prison. Its walls are not code, but silicon, light, and hundreds of manufacturing processes precise down to the nanometer. The name of this prison is TSMC. And a significant portion of the bricks that built it\u2014the process experiences that taught TSMC how to manufacture massive chips\u2014were paid for by gamers."}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.h2,{id:"i-an-uncomfortable-fact",children:"I. An Uncomfortable Fact"}),"\n",(0,s.jsx)(n.p,{children:"Before unfolding the argument, let's get one thing straight."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"The launch customer for TSMC's advanced processes is not gaming. It is Apple."})}),"\n",(0,s.jsx)(n.p,{children:"In September 2018, the Apple A12 Bionic became the first mass-produced TSMC 7nm chip. In 2020, the A14 Bionic pioneered 5nm. In 2022, the A16 Bionic debuted 4nm. In 2023, the A17 Pro debuted 3nm. With every generational shift in process technology, the iPhone is always the first to charge ahead."}),"\n",(0,s.jsx)(n.p,{children:"In 2023, the revenue breakdown of TSMC's customers: Apple accounted for 25%, NVIDIA 11%, and AMD 7%. The biggest customer is Apple, not any company related to gaming."}),"\n",(0,s.jsx)(n.p,{children:"This fact must be honestly acknowledged. The arguments in this book do not rely on hyperbole."}),"\n",(0,s.jsx)(n.p,{children:"But numbers only tell half the story. Apple is TSMC's largest customer and most loyal launch partner\u2014this is indisputable. However, the reason TSMC could become the only factory on Earth capable of mass-producing the most advanced chips does not rely on any single customer. It relies on an entire customer portfolio\u2014and within this portfolio, the role played by gaming is far deeper than the revenue numbers suggest."}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.h2,{id:"ii-four-types-of-chips-four-types-of-exam-papers",children:"II. Four Types of Chips, Four Types of Exam Papers"}),"\n",(0,s.jsxs)(n.p,{children:["To understand gaming's true contribution to TSMC, one must first understand something everyone in the semiconductor industry knows but rarely explains to outsiders: ",(0,s.jsx)(n.strong,{children:"Not all chips are equally hard to make."})]}),"\n",(0,s.jsx)(n.p,{children:"Every new process node at TSMC\u2014for example, jumping from 7nm to 5nm\u2014is like a newly built examination hall. The hall is built, but to verify if it works, you need examinees to come in and take a test. Different examinees take papers of different difficulty levels."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"The Mobile SoC is the foundational paper."})}),"\n",(0,s.jsxs)(n.p,{children:["Apple's A-series chips have a die area of about 110 square millimeters. Small chips, low power consumption, updated annually. Its requirement for TSMC is: prove that this new node ",(0,s.jsx)(n.strong,{children:"can work"}),"\u2014the transistors can function, the yield is high enough, and power consumption meets targets. This is the maiden voyage experiment. Apple is willing to pay top dollar to grab the first batch of capacity, and TSMC uses Apple's orders to recoup the cost of building the new node's fab. Both sides get what they need."]}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"The Gaming GPU is the extreme paper."})}),"\n",(0,s.jsxs)(n.p,{children:["NVIDIA's RTX 4090\u2014the flagship consumer graphics card of 2022\u2014houses a die of 608 square millimeters, 76 billion transistors, and consumes 450 watts. Using the exact same 5nm family process, Apple makes a chip the size of a fingertip, while NVIDIA makes a monster ",(0,s.jsx)(n.strong,{children:"five and a half times larger"})," than Apple's chip."]}),"\n",(0,s.jsx)(n.p,{children:"The difficulty of manufacturing a large die does not increase linearly\u2014it increases exponentially. Defect distribution on a wafer is random; the larger the die area, the higher the probability of hitting a defect. A twelve-inch wafer yields fewer large dies, making the cost of each one higher. To get a 608-square-millimeter die to commercial mass production yields, TSMC's engineers must push the control precision of the entire process to its absolute limit\u2014every photolithography exposure, every etching depth, the alignment of every layer of metal interconnects\u2014all must be flawless."}),"\n",(0,s.jsxs)(n.p,{children:['Apple\'s A-series chips verified that "this node can make mobile SoCs." ',(0,s.jsx)(n.strong,{children:"NVIDIA's and AMD's gaming GPUs verified that \"this node can achieve the most extreme things.\""})," The former is an entrance exam; the latter is a stress test."]}),"\n",(0,s.jsx)(n.p,{children:"Without the stress test, TSMC wouldn't know how its process behaves under extreme conditions."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"The Console SoC is the endurance paper."})}),"\n",(0,s.jsx)(n.p,{children:"The heart of the PlayStation 5 is a custom chip by AMD\u2014a Zen 2 CPU plus an RDNA 2 GPU, produced on TSMC's 7nm. So is the Xbox Series X\u2014the same architecture, the same foundry, the same process. Even the Steam Deck mentioned in Chapter 6 uses the AMD Aerith APU, also on TSMC's 7nm."}),"\n",(0,s.jsx)(n.p,{children:"Three machines, one production line."}),"\n",(0,s.jsxs)(n.p,{children:["What makes consoles unique is their product cycle. The lifespan of a console generation is seven to ten years. Console manufacturers will not change chip suppliers during the entire lifecycle\u2014you can't go to Sony three years after the PS5's launch and say, \"Let's switch to Samsung.\" This means that what TSMC gets from Sony and Microsoft is an ",(0,s.jsx)(n.strong,{children:"ultra-long-term, ultra-stable, predictable order"}),"."]}),"\n",(0,s.jsx)(n.p,{children:"The PS5 has shipped over 60 million units to date. The Xbox Series X/S over 30 million. The Steam Deck roughly 5.6 million. Inside every one of them is a TSMC 7nm chip."}),"\n",(0,s.jsx)(n.p,{children:"The iPhone is an annual update\u2014volume surges in September and begins to trail off the following March. This rhythm creates clear peaks and troughs in capacity utilization. What the console orders fill are exactly those capacity voids during the iPhone's off-season. They keep TSMC's fab utilization rate at a high level year-round\u2014and a high utilization rate is the prerequisite for TSMC to continue pouring astronomical capital into building next-generation nodes."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"The AI Training Chip is the harvest paper."})}),"\n",(0,s.jsx)(n.p,{children:"The NVIDIA H100, launched in 2022, drove the training of ChatGPT. TSMC N4 process\u2014a refined version of 5nm. Die area over 800 square millimeters. Power consumption over 700 watts. A single card retails between $25,000 and $40,000."}),"\n",(0,s.jsx)(n.p,{children:"How was the H100 built?"}),"\n",(0,s.jsx)(n.p,{children:'The N4 process it uses is the crystallization of TSMC\'s accumulated mass production experience in the 5nm generation. And the mass production yield of large 5nm dies\u2014the number that determines whether "this 800-square-millimeter chip can be commercialized"\u2014was verified by NVIDIA using the RTX 30 and RTX 40 series gaming graphics cards.'}),"\n",(0,s.jsx)(n.p,{children:"Gaming GPUs came first, the stress test was completed, and the large die process details were fine-tuned. AI chips came later, walking directly on the path paved by gaming GPUs."}),"\n",(0,s.jsx)(n.p,{children:"Four exam papers, four contributions:"}),"\n",(0,s.jsxs)(n.ul,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Apple:"}),' Maiden experiment \u2014 "This node can work."']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Gaming GPUs:"}),' Stress test \u2014 "This node can be pushed to the limit."']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Console SoCs:"}),' Long-term orders \u2014 "This production line is worth keeping alive."']}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"AI Chips:"}),' Harvest \u2014 "The large die process verified by gaming is now used to make even larger dies."']}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"Remove gaming, and this cycle loses two pieces\u2014the stress test and the long-term orders. Without the stress test, TSMC wouldn't know how far its process could be pushed. Without long-term orders, TSMC's fab utilization wouldn't hold up, and investment decisions for the next node would waver."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"AI chips did not fall from the sky. They grew standing on the shoulders of gaming GPUs."})}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.h2,{id:"iii-the-moat-of-trust",children:"III. The Moat of Trust"}),"\n",(0,s.jsx)(n.p,{children:"But a customer portfolio alone isn't enough. Is there a second foundry on Earth that can do advanced processes?"}),"\n",(0,s.jsx)(n.p,{children:"Yes. Samsung. And Intel is trying."}),"\n",(0,s.jsx)(n.p,{children:"Samsung's advanced process technology, on paper, is not far behind TSMC's. Samsung's 3nm GAA (Gate-All-Around) transistors even reached mass production earlier than TSMC's. Under Pat Gelsinger, Intel introduced the Intel 18A process, publicly claiming its performance catches up to TSMC's N3."}),"\n",(0,s.jsx)(n.p,{children:"But the reality in 2026 is: The world's most advanced AI chips, most advanced mobile processors, most advanced gaming GPUs\u2014almost all are manufactured by TSMC. Samsung and Intel's combined market share in advanced processes is less than a fraction of TSMC's."}),"\n",(0,s.jsx)(n.p,{children:"Why?"}),"\n",(0,s.jsxs)(n.p,{children:["Not because Samsung and Intel's engineers are worse than TSMC's. It's because TSMC has a moat that other companies ",(0,s.jsx)(n.strong,{children:"cannot replicate"}),"."]}),"\n",(0,s.jsxs)(n.p,{children:["The name of this moat is ",(0,s.jsx)(n.strong,{children:"trust"}),"."]}),"\n",(0,s.jsx)(n.p,{children:"Samsung's problem is called playing \"both player and referee\" in the industry. Samsung is the world's largest memory chip maker, the world's second-largest mobile phone brand, and simultaneously operates a foundry business. When a fabless chip company\u2014like Qualcomm\u2014hands over its most advanced chip blueprints to Samsung for manufacturing, a question arises in its mind: If Samsung's semiconductor division sees my design, will they leak critical information to Samsung's mobile phone division? Samsung's mobile phone division is competing directly with my clients."}),"\n",(0,s.jsx)(n.p,{children:"Samsung pledges solemnly that there is a firewall between the two divisions. But solemn pledges do not make a moat."}),"\n",(0,s.jsxs)(n.p,{children:["Intel's problem runs deeper than Samsung's. Samsung's problem is \"player and referee\"\u2014a conflict of interest. Intel's problem is its ",(0,s.jsx)(n.strong,{children:"criminal record"}),"."]}),"\n",(0,s.jsx)(n.p,{children:"In 2003, AMD launched the Athlon 64 processor. From a purely technical standpoint, the Athlon 64 crushed Intel's contemporaneous Pentium 4\u2014higher instructions per clock, lower power consumption, a more advanced 64-bit architecture. That was the only period in the history of x86 processors where AMD comprehensively led Intel in performance."}),"\n",(0,s.jsx)(n.p,{children:"According to normal market logic, consumers should have voted with their feet, and AMD's market share should have skyrocketed."}),"\n",(0,s.jsx)(n.p,{children:"It didn't."}),"\n",(0,s.jsx)(n.p,{children:"Because Intel used a different set of logic."}),"\n",(0,s.jsx)(n.p,{children:'Intel offered massive "exclusive rebates" to the world\'s largest PC brands\u2014Dell, HP, Lenovo, Acer, NEC. The deal was simple: use only Intel CPUs, and I will give you hundreds of millions of dollars in subsidies; if you dare to stock a single AMD chip, the subsidies get slashed entirely.'}),"\n",(0,s.jsxs)(n.p,{children:["Dell was the most extreme case. From 2003 to 2006, Intel paid Dell approximately $4.3 billion in exclusive subsidies. This money grew from 10% of Dell's operating profit in 2003 all the way to 38% in 2006. By the first quarter of 2007, it accounted for 76%. In other words\u2014",(0,s.jsx)(n.strong,{children:"over three-quarters of Dell's profits came from Intel's subsidies, not from selling computers."})," Dell had transformed from a computer company into Intel's subsidy ATM."]}),"\n",(0,s.jsx)(n.p,{children:"In exchange, for those few years, Dell did not ship a single AMD desktop computer. Zero."}),"\n",(0,s.jsx)(n.p,{children:"Not because AMD's products were bad\u2014all benchmarks proved the Athlon 64 was faster. It was because Dell had done the math: using AMD chips might save a few dozen dollars in component costs per computer, but if Intel cut off over a billion dollars in annual subsidies, Dell's financials would instantly collapse."}),"\n",(0,s.jsx)(n.p,{children:"In 2006, Dell finally began selling AMD computers. Intel retaliated immediately\u2014slashing the subsidies. Dell's operating profit plummeted the next quarter."}),"\n",(0,s.jsx)(n.p,{children:"In 2009, the European Commission hit Intel with a \u20ac1.06 billion antitrust fine\u2014the largest fine against a single company in EU history at the time. That same year, Intel paid AMD $1.25 billion in a settlement. The US Federal Trade Commission (FTC) also filed a lawsuit in 2009, and in 2010 Intel signed a settlement agreeing to cease all exclusive rebate practices."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"What does this history have to do with TSMC?"})}),"\n",(0,s.jsx)(n.p,{children:"Everything."}),"\n",(0,s.jsx)(n.p,{children:"In the early 2000s, Intel used channel bullying to maintain its monopoly in the x86 market. It didn't win on technology\u2014its Pentium 4 lost to the Athlon 64 in performance. It won by using tens of billions of dollars in subsidies and threats to block AMD's sales channels."}),"\n",(0,s.jsxs)(n.p,{children:["This tactic worked in the short term. But it had a fatal side effect\u2014",(0,s.jsx)(n.strong,{children:"it made Intel think it didn't need to go all-in on manufacturing."})]}),"\n",(0,s.jsx)(n.p,{children:'Why bother catching up in process technology? The OEMs were all locked in by rebates anyway; even if AMD made a better chip, they couldn\'t sell it. Why consider spinning off the manufacturing business and embracing the fabless model? The "design plus manufacturing all-in-one" IDM model had always worked fine\u2014relying not on manufacturing efficiency, but on channel control.'}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Intel's rebate case masked the fact that the IDM model was rotting from the inside."}),' While Intel was busy using rebates to choke AMD from 2003 to 2007, TSMC was quietly doing something: upgrading from a "cheap foundry" to a "more advanced foundry than Intel." In 2018, when TSMC\'s 7nm entered mass production, Intel\'s 10nm was still struggling. That same year\u2014Intel\'s process advantage, the core moat this company had maintained for over twenty years, officially flipped.']}),"\n",(0,s.jsx)(n.p,{children:"The sense of security bought by rebates ultimately caused Intel to miss the era shift in semiconductor manufacturing."}),"\n",(0,s.jsx)(n.p,{children:"And this history had another consequence."}),"\n",(0,s.jsxs)(n.p,{children:["In 2009, the exact same year the Intel rebate case exploded, AMD made a desperate decision\u2014",(0,s.jsx)(n.strong,{children:"to spin off its own foundries and establish GlobalFoundries."})," AMD didn't want to spin them off. It was forced to. Intel's rebate war pushed AMD to the brink of bankruptcy, and AMD could no longer afford to maintain its own fabs. Spinning them off was a matter of survival."]}),"\n",(0,s.jsx)(n.p,{children:"Ironically, this desperate decision for survival became the prerequisite for AMD's future rise."}),"\n",(0,s.jsx)(n.p,{children:"After ditching its fabs, AMD became a pure design company\u2014fabless. It could freely choose its foundries. In 2014, a newly appointed CEO named Lisa Su made a crucial decision: to hand over all of AMD's most advanced chips to TSMC. Zen architecture, RDNA architecture, PS5 SoCs, Xbox Series X SoCs, Steam Deck APUs\u2014all manufactured by TSMC."}),"\n",(0,s.jsx)(n.p,{children:"Intel used rebates to push AMD to bankruptcy \u2192 AMD was forced to ditch its fabs \u2192 AMD embraced TSMC \u2192 TSMC received AMD's orders, making its customer portfolio more diverse and its process experience denser \u2192 TSMC's virtuous cycle spun faster \u2192 Intel's own process was subsequently overtaken by TSMC."}),"\n",(0,s.jsxs)(n.p,{children:[(0,s.jsx)(n.strong,{children:"Intel's rebate case was the biggest helper in TSMC's rise."})," It did two things: first, it paralyzed Intel in the comfort zone of IDM until it missed the process node transition; second, it forced AMD to become fabless, delivering to TSMC a super-customer that would later supply the hearts of all three major consoles."]}),"\n",(0,s.jsx)(n.p,{children:'This is the difference between "hegemony" (ruling by force) and "the king\'s way" (ruling by virtue). Intel relied on threats and rebates\u2014"If you don\'t use my chips, I\'ll cut your subsidies." TSMC relied on trust and service\u2014"Give me your core designs, and I will never compete with you."'}),"\n",(0,s.jsx)(n.p,{children:"Twenty years later, Intel wanted to pivot to the foundry business (IDM 2.0), knocking on the doors of NVIDIA, AMD, and Apple, asking if they were willing to let Intel manufacture their chips."}),"\n",(0,s.jsx)(n.p,{children:"They looked at Intel's criminal record\u2014a company that once bought off Dell with $4.3 billion in rebates and suppressed the entire OEM supply chain with threats\u2014and politely said: No, thank you."}),"\n",(0,s.jsx)(n.p,{children:'Intel said it would treat foundry customers fairly. But when a company with a history of bullying says "I\'m a good guy now," compared to a company that has never had a conflict of interest since day one\u2014who would you trust?'}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"TSMC's genius lay in Morris Chang making what looked like the dumbest decision in 1987: not making its own products."})}),"\n",(0,s.jsx)(n.p,{children:"TSMC is a Pure Foundry. It does not design any chips, it does not sell any end products, and it does not compete with any customers. Apple hands the blueprints of the A-series to TSMC without worrying TSMC will use them to make its own phones. NVIDIA hands over GPU blueprints without worrying TSMC will make its own graphics cards. AMD, Qualcomm, Broadcom, MediaTek\u2014every fabless chip company in the world can hand their core intellectual property to TSMC without any hesitation."}),"\n",(0,s.jsx)(n.p,{children:"Because there is zero business overlap between TSMC and them. Zero."}),"\n",(0,s.jsxs)(n.p,{children:["This business model doesn't sound like some profound strategy. But its effect is: ",(0,s.jsx)(n.strong,{children:"Every company in the world that wants to make the most advanced chips converges on the same foundry."})," Convergence brings diversity, diversity brings density of process experience, density of process experience brings yield advantages, and yield advantages bring more customers\u2014a virtuous cycle spinning faster and faster."]}),"\n",(0,s.jsxs)(n.p,{children:["What Samsung and Intel have to catch up to isn't just TSMC's technology. They have to catch up to the ",(0,s.jsx)(n.strong,{children:"trust"})," the global fabless ecosystem has accumulated in TSMC over thirty years. You can't catch up with a slide deck. You can't catch up in a quarter. You can't even catch up in a decade\u2014because trust is not a technology that can be researched and developed; it is an irreversible ecological relationship."]}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.h2,{id:"iv-gamings-invisible-bill",children:"IV. Gaming's Invisible Bill"}),"\n",(0,s.jsx)(n.p,{children:"Now we can string together the core argument of this chapter."}),"\n",(0,s.jsx)(n.p,{children:"In early 2024, an AI research lab\u2014maybe in San Francisco, maybe in London, maybe in Beijing\u2014received a newly arrived batch of NVIDIA H100 GPUs. Engineers racked them up, connected them to the network, and began training a large language model."}),"\n",(0,s.jsx)(n.p,{children:"They would never think about the following chain:"}),"\n",(0,s.jsxs)(n.ol,{children:["\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"The H100 is produced using TSMC's N4 process."})," N4 is a refined version of the 5nm family."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"The mass production yield of large 5nm dies was verified by NVIDIA using RTX 30 and RTX 40 series gaming graphics cards."})," The RTX 4090's 608-square-millimeter die and 76 billion transistors\u2014among all chips of its generation, it was the most extreme stress test TSMC's 5nm process faced."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"Gamers paid $1,599 to buy an RTX 4090."})," A portion of that money became the foundry fee NVIDIA paid TSMC, became the engineering budget TSMC used to optimize large die yields, and became the process foundation that allowed the H100 to be mass-produced."]}),"\n",(0,s.jsxs)(n.li,{children:[(0,s.jsx)(n.strong,{children:"During the same period, Sony and Microsoft placed long-term orders for tens of millions of console SoCs with TSMC annually."})," These orders filled the capacity utilization of TSMC's 7nm fabs, giving TSMC stable cash flow to invest in the next node. Every PS5 and Xbox Series X shipped was a stepping stone on TSMC's path to 3nm and 2nm."]}),"\n",(0,s.jsx)(n.li,{children:(0,s.jsx)(n.strong,{children:"When TSMC's 3nm process matured enough to mass-produce AI chips, its large die process experience, its moat of customer diversity, and its fab utilization foundation\u2014all had the fingerprints of gaming on them."})}),"\n"]}),"\n",(0,s.jsx)(n.p,{children:"This is not a metaphor. It is the very real intersection of three threads: capital flow, engineering experience, and capacity planning."}),"\n",(0,s.jsxs)(n.p,{children:["The conclusion of Chapter 7 was: ",(0,s.jsx)(n.strong,{children:"Every gamer who bought a GeForce is a co-funder of the AI revolution\u2014their money nourished the software prison that is CUDA."})]}),"\n",(0,s.jsxs)(n.p,{children:["The conclusion of this chapter is the other half of that same sentence: ",(0,s.jsx)(n.strong,{children:"Their money, simultaneously, nourished the physical arsenal that is TSMC."})]}),"\n",(0,s.jsx)(n.p,{children:"Every cent NVIDIA collected in the gaming market became the R&D fund for TSMC to evolve the next-generation process. What gamers paid for wasn't just CUDA's software lock-in\u2014they also paid for the silicon foundation that AI chips rely on to exist. Two independent mechanisms, the same group of victims, the same set of beneficiaries."}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.h2,{id:"v-closing-arguments",children:"V. Closing Arguments"}),"\n",(0,s.jsx)(n.p,{children:"That pattern has appeared again. For the sixth time."}),"\n",(0,s.jsxs)(n.p,{children:["The prototype in Chapter 2: ",(0,s.jsx)(n.strong,{children:"Microsoft uses DirectX's convenience to attract developers \u2192 Developers are locked into Windows \u2192 Consumers are locked in turn."})]}),"\n",(0,s.jsxs)(n.p,{children:["The variation in this chapter: ",(0,s.jsx)(n.strong,{children:"Gaming verifies advanced processes \u2192 AI chips borrow gaming's process experience \u2192 Gamers become co-funders of the AI revolution."})]}),"\n",(0,s.jsxs)(n.p,{children:["But this time's variation has a crucial difference\u2014",(0,s.jsx)(n.strong,{children:"the lock is not at the API layer, not at the software layer. The lock is at the physical layer."})]}),"\n",(0,s.jsx)(n.p,{children:"DirectX's lock is built with code\u2014so Valve could use another pile of code to bypass it. CUDA's lock is built by stacking four layers of software ecosystem\u2014so AMD chased for ten years and still hasn't caught up."}),"\n",(0,s.jsx)(n.p,{children:"TSMC's lock is structural."}),"\n",(0,s.jsx)(n.p,{children:'What it locks is not an API, not a framework, not a knowledge system. What it locks is thirty years of trust from the global fabless ecosystem toward a single company, the process experience accumulated by dozens of clients on the same production line, and the irreversible ecological relationship created by a business model so simple it doesn\'t even sound like a moat: "We do not compete with our customers."'}),"\n",(0,s.jsx)(n.p,{children:"Samsung cannot catch up. Not because its engineers are bad\u2014Samsung's semiconductor team is world-class. It's because its identity as both player and referee makes high-value clients like Apple, NVIDIA, and AMD too afraid to hand over their most advanced designs. Without these clients, Samsung's advanced processes lack the stress tests, the diversified experience, and the virtuous cycle."}),"\n",(0,s.jsx)(n.p,{children:"Intel cannot catch up. Not because Pat Gelsinger's vision was wrong\u2014the logic of IDM 2.0 works on paper. It's because Intel's conflict of interest in operating both CPU design and wafer foundry makes external clients distrust its priorities. The next chapter will tell Gelsinger's story\u2014the tragedy of someone technically correct but disallowed by the system to execute."}),"\n",(0,s.jsx)(n.p,{children:"The reason they can't catch up is not a technology gap. The reason they can't catch up is a trust gap. And a trust gap is something grown over time\u2014you can't buy it with money, and spending time to chase it might not even work, because the person running ahead is still accumulating trust."}),"\n",(0,s.jsxs)(n.p,{children:["The lock in Chapter 6 is shallow\u2014a single API layer, pryable. The lock in Chapter 7 is deep\u2014four layers of software ecosystem, unpryable. The lock in this chapter is ",(0,s.jsx)(n.strong,{children:"structural"}),"\u2014it wasn't designed by any one person; it was grown unintentionally by an entire industry over thirty years. You wouldn't even know where to pry."]}),"\n",(0,s.jsx)(n.p,{children:"Three types of locks, three depths. So far, only the shallowest one has ever been pried open. And the one who pried it open\u2014Valve\u2014just built a new wall of its own."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.strong,{children:"This is the true face of technological hegemony. It is not a card game where you can turn the tables. It is a geological structure built layer upon layer\u2014the topmost surface may occasionally be eroded by wind and rain, but the bedrock underneath remains completely unmoved."})}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.h2,{id:"vi-the-loot-is-still-being-divided",children:"VI. The Loot is Still Being Divided"}),"\n",(0,s.jsx)(n.p,{children:"Back to the NVIDIA supply chain manager at the beginning."}),"\n",(0,s.jsx)(n.p,{children:"He waited three days, and TSMC's reply was: The production schedule cannot be moved up. Ahead in line are Apple, AMD, Qualcomm, and several clients he is not allowed to know the names of."}),"\n",(0,s.jsx)(n.p,{children:'He treated this as a capacity management problem\u2014"TSMC is too busy; they just need to expand their fabs next year."'}),"\n",(0,s.jsx)(n.p,{children:"No."}),"\n",(0,s.jsx)(n.p,{children:'TSMC being "too busy" is not a capacity problem. It is a structural problem. Every company in the world that wants to make the most advanced chips is concentrated in the exact same factory\u2014not because there are no choices, but because the only choice spent thirty years, brick by brick, building an fortress no one can replicate, using a business model that doesn\'t compete with you, using gaming GPUs for stress tests, using console SoCs for long-term orders, using Apple for maiden experiments.'}),"\n",(0,s.jsx)(n.p,{children:"And within this fortress, the easiest bricks to overlook\u2014the 608-square-millimeter dies of the stress-test GPUs, the console chips filling the off-season capacity\u2014all have the name of gaming carved into them."}),"\n",(0,s.jsx)(n.p,{children:"The B200 order he placed with TSMC, every card his company sells to global AI labs, every cent of premium the global AI industry pays to wait in line for a silicon chip\u2014all trace back to the same thread:"}),"\n",(0,s.jsx)(n.p,{children:"Someone wanted to play a better game."}),"\n",(0,s.jsx)(n.p,{children:"That bill has not yet been settled. Moreover, the amount on the bill is inflating uncontrollably. Because for TSMC to continue building the next generation\u20142nm, 1.4nm\u2014the required capital expenditure has surged to over $30 billion a year. A portion of this money will come from NVIDIA's revenue from selling gaming graphics cards. It will come from AMD's console contracts. It will come from the pocket of every gamer who spends $1,599 to buy an RTX 5090."}),"\n",(0,s.jsx)(n.p,{children:"These gamers don't know what they are paying for."}),"\n",(0,s.jsx)(n.p,{children:"They only know the new cards run faster, ray tracing looks more beautiful, and frame rates are higher. They discuss price-to-performance ratios in communities, discuss power consumption, discuss whether to wait for the next generation."}),"\n",(0,s.jsx)(n.p,{children:"They don't know their money is nourishing an arsenal. And the things built inside that arsenal are reshaping the direction of human civilization."}),"\n",(0,s.jsx)(n.hr,{}),"\n",(0,s.jsx)(n.p,{children:"But the bill is not just money. There is another side to the bill."}),"\n",(0,s.jsxs)(n.p,{children:["Every chip TSMC builds\u2014whether it's for an iPhone, a PlayStation, a Steam Deck, or an H100\u2014needs someone to ",(0,s.jsx)(n.strong,{children:"design"})," it. Designing GPU architectures is the job of NVIDIA and AMD. Designing console SoCs is the job of AMD. And the reason AMD can simultaneously design the chip for the PS5, the chip for the Xbox Series X, and the chip for the Steam Deck\u2014the hearts of all three major platforms coming from the exact same company\u2014is because someone made a decision a decade ago that everyone laughed at."]}),"\n",(0,s.jsx)(n.p,{children:"That person's name is Lisa Su. That decision was to abandon AMD's own fabs and fully embrace TSMC."}),"\n",(0,s.jsx)(n.p,{children:"That is the story of the next chapter."}),"\n",(0,s.jsx)(n.p,{children:(0,s.jsx)(n.img,{src:t(5158).A+"",width:"2816",height:"1536"})})]})}function d(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,s.jsx)(n,{...e,children:(0,s.jsx)(c,{...e})}):c(e)}},5158(e,n,t){t.d(n,{A:()=>s});const s=t.p+"assets/images/ch08_en-02b422f85f8079c400a557d2bd08fccf.png"},8453(e,n,t){t.d(n,{R:()=>a,x:()=>r});var s=t(6540);const i={},o=s.createContext(i);function a(e){const n=s.useContext(o);return s.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function r(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:a(e.components),s.createElement(o.Provider,{value:n},e.children)}}}]);